import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku } from '@sudoku/sudoku';
import { derived, get, writable } from 'svelte/store';
import { createGame, createSudoku } from '../../../domain/index.js';
import { hints } from './hints';

/**
 * 创建一个空的 9x9 数独网格。
 *
 * 适配层在尚未创建领域对象时需要发布一个稳定的空状态，
 * 这样 UI 订阅方不需要额外处理 undefined。
 * @returns {number[][]}
 */
function createEmptyGrid() {
	return Array.from({ length: 9 }, () => Array(9).fill(0))
}

/**
 * 将领域层冲突坐标转换为 UI 使用的单元格 key。
 *
 * UI 组件使用 "x,y" 形式定位格子；领域层使用 row/col。
 * 这个函数只做坐标表达转换，不重新判断数独冲突规则。
 * @param {{ row: number, col: number }[]} conflicts
 * @returns {string[]}
 */
function toConflictKeys(conflicts) {
	return conflicts.map(({ row, col }) => `${col},${row}`)
}

/**
 * 创建空的瞬时提示状态。
 *
 * 候选提示和下一步提示都依赖当前盘面；盘面一旦变化，
 * 旧提示就可能不再成立，因此统一用 null 表示“当前没有有效提示”。
 * @returns {null}
 */
function createEmptyHint() {
	return null
}

/**
 * 创建未进入 Explore Mode 时的默认探索状态。
 *
 * 这个对象的字段与 Game.getExploreState() 保持一致，
 * 让 UI 无论是否已经开始游戏，都能读取同一套状态结构。
 * @returns {{
 *  active: boolean,
 *  hasConflict: boolean,
 *  isKnownFailure: boolean,
 *  canCommit: boolean,
 *  canReset: boolean,
 *  canDiscard: boolean,
 *  currentDepth: number,
 *  failedPathCount: number,
 * }}
 */
function createIdleExploreState() {
	return {
		active: false,
		hasConflict: false,
		isKnownFailure: false,
		canCommit: false,
		canReset: false,
		canDiscard: false,
		currentDepth: 0,
		failedPathCount: 0,
	}
}

/**
 * 创建面向 Svelte 的领域游戏 store。
 *
 * 这个 store 是 UI 与 Game/Sudoku 之间的适配层：
 * - 领域对象负责规则、历史、提示和 Explore Mode；
 * - store 负责把领域状态发布为响应式数据；
 * - 组件只读取 store 状态并发送命令。
 *
 * @returns {{
 *  subscribe: import('svelte/store').Writable<any>['subscribe'],
 *  generate: (difficulty: any) => void,
 *  decodeSencode: (sencode: string) => void,
 *  getSencode: () => string,
 *  getCurrentGrid: () => number[][],
 *  guess: (pos: {x:number,y:number}|null, value: number) => boolean,
 *  applyHint: (pos: {x:number,y:number}|null) => boolean,
 *  showCellHint: (pos: {x:number,y:number}|null) => any,
 *  showNextHint: () => any,
 *  clearHints: () => void,
 *  startExplore: () => boolean,
 *  resetExplore: () => boolean,
 *  commitExplore: () => boolean,
 *  discardExplore: () => boolean,
 *  undo: () => void,
 *  redo: () => void,
 * }}
 */
function createDomainGameStore() {
	const state = writable({
		puzzleGrid: createEmptyGrid(),
		userGrid: createEmptyGrid(),
		invalidCells: [],
		canUndo: false,
		canRedo: false,
		won: false,
		candidateHint: createEmptyHint(),
		nextHint: createEmptyHint(),
		explore: createIdleExploreState(),
	})

	/** @type {ReturnType<typeof createGame> | null} 当前被适配层持有的领域游戏对象 */
	let game = null
	/** @type {ReturnType<ReturnType<typeof createGame>['getCellHint']> | null} 当前选中格子的候选提示 */
	let candidateHint = createEmptyHint()
	/** @type {ReturnType<ReturnType<typeof createGame>['getNextHint']> | null} 当前盘面的下一步提示 */
	let nextHint = createEmptyHint()

	/**
	 * 清理所有依赖当前盘面的瞬时提示。
	 *
	 * 任何写盘面、撤销、重做、探索提交或回滚操作之后，
	 * 原先的候选提示/下一步提示都可能过期，因此统一清空。
	 */
	function clearTransientHints() {
		candidateHint = createEmptyHint()
		nextHint = createEmptyHint()
	}

	/**
	 * 将领域对象的当前状态发布到 Svelte store。
	 *
	 * 题面、玩家盘面、冲突、胜利、历史能力和 Explore 状态
	 * 都从 Game/Sudoku 导出，避免适配层维护第二份业务事实。
	 */
	function publish() {
		if (!game) {
			state.set({
				puzzleGrid: createEmptyGrid(),
				userGrid: createEmptyGrid(),
				invalidCells: [],
				canUndo: false,
				canRedo: false,
				won: false,
				candidateHint: createEmptyHint(),
				nextHint: createEmptyHint(),
				explore: createIdleExploreState(),
			})
			return
		}

		const sudoku = game.getSudoku()
		state.set({
			puzzleGrid: sudoku.getGivens(),
			userGrid: sudoku.getGrid(),
			invalidCells: toConflictKeys(sudoku.getConflicts()),
			canUndo: game.canUndo(),
			canRedo: game.canRedo(),
			won: sudoku.isSolved(),
			candidateHint,
			nextHint,
			explore: game.getExploreState(),
		})
	}

	/**
	 * 使用指定题面启动新游戏。
	 *
	 * 这里会重新创建 Game，因此主局面 history、Explore 会话和瞬时提示都会重置。
	 * @param {number[][]} nextPuzzleGrid
	 */
	function startFromGrid(nextPuzzleGrid) {
		game = createGame({ sudoku: createSudoku(nextPuzzleGrid) })
		clearTransientHints()
		publish()
	}

	return {
		subscribe: state.subscribe,

		/**
		 * 生成指定难度的新题面并开始游戏。
		 * @param {any} difficulty
		 */
		generate(difficulty) {
			startFromGrid(generateSudoku(difficulty))
		},

		/**
		 * 从分享编码恢复题面并开始游戏。
		 * @param {string} sencode
		 */
		decodeSencode(sencode) {
			startFromGrid(decodeSencode(sencode))
		},

		/**
		 * 获取当前题面的分享编码。
		 *
		 * 分享编码只基于 givens，而不是玩家当前填写的 userGrid。
		 * @returns {string}
		 */
		getSencode() {
			if (!game) {
				return encodeSudoku(createEmptyGrid())
			}

			return encodeSudoku(game.getSudoku().getGivens())
		},

		/**
		 * 获取当前玩家盘面快照。
		 * @returns {number[][]}
		 */
		getCurrentGrid() {
			return get(state).userGrid
		},

		/**
		 * 在指定 UI 坐标写入一个玩家输入。
		 *
		 * UI 使用 x/y，领域层使用 row/col，因此这里完成坐标映射。
		 * @param {{x:number,y:number}|null} pos
		 * @param {number} value
		 * @returns {boolean}
		 */
		guess(pos, value) {
			if (!game || pos?.x === null || pos?.y === null) {
				return false
			}

			const changed = game.guess({ row: pos.y, col: pos.x, value })
			if (changed) {
				clearTransientHints()
			}
			publish()
			return changed
		},

		/**
		 * 对指定格子应用直接填答案式提示。
		 *
		 * 只有领域层实际写入成功时才消耗一次 hint 次数。
		 * @param {{x:number,y:number}|null} pos
		 * @returns {boolean}
		 */
		applyHint(pos) {
			if (!game || pos?.x === null || pos?.y === null) {
				return false
			}

			const applied = game.applyHint({
				row: pos.y,
				col: pos.x,
			})
			if (applied) {
				hints.useHint()
				clearTransientHints()
			}
			publish()
			return applied
		},

		/**
		 * 显示当前选中格子的候选提示。
		 *
		 * 候选提示与下一步提示互斥展示，避免 UI 同时显示两套指向不同格子的提示。
		 * @param {{x:number,y:number}|null} pos
		 * @returns {ReturnType<ReturnType<typeof createGame>['getCellHint']> | null}
		 */
		showCellHint(pos) {
			if (!game || pos?.x === null || pos?.y === null) {
				candidateHint = createEmptyHint()
				publish()
				return null
			}

			candidateHint = game.getCellHint({ row: pos.y, col: pos.x })
			nextHint = createEmptyHint()
			publish()
			return candidateHint
		},

		/**
		 * 显示当前盘面的下一步推定提示。
		 *
		 * Game 会根据当前活跃局面决定是在主盘面还是 Explore 分支上计算。
		 * @returns {ReturnType<ReturnType<typeof createGame>['getNextHint']> | null}
		 */
		showNextHint() {
			if (!game) {
				nextHint = createEmptyHint()
				publish()
				return null
			}

			nextHint = game.getNextHint()
			candidateHint = createEmptyHint()
			publish()
			return nextHint
		},

		/**
		 * 手动清空当前候选提示与下一步提示。
		 */
		clearHints() {
			clearTransientHints()
			publish()
		},

		/**
		 * 进入 Explore Mode。
		 * @returns {boolean}
		 */
		startExplore() {
			if (!game) {
				return false
			}

			const started = game.startExplore()
			if (started) {
				clearTransientHints()
			}
			publish()
			return started
		},

		/**
		 * 将 Explore 分支回滚到进入探索时的起点。
		 * @returns {boolean}
		 */
		resetExplore() {
			if (!game) {
				return false
			}

			const reset = game.resetExplore()
			if (reset) {
				clearTransientHints()
			}
			publish()
			return reset
		},

		/**
		 * 将 Explore 分支提交回主局面。
		 * @returns {boolean}
		 */
		commitExplore() {
			if (!game) {
				return false
			}

			const committed = game.commitExplore()
			const exploreStillActive = game.getExploreState().active
			// 提交失败时通常仍停留在 Explore 分支，保留提示能帮助玩家继续修复冲突；
			// 只有提交成功或空提交导致 Explore 结束时，才清理已经脱离当前上下文的瞬时提示。
			if (!exploreStillActive) {
				clearTransientHints()
			}
			publish()
			return committed
		},

		/**
		 * 放弃 Explore 分支并回到主局面。
		 * @returns {boolean}
		 */
		discardExplore() {
			if (!game) {
				return false
			}

			const discarded = game.discardExplore()
			if (discarded) {
				clearTransientHints()
			}
			publish()
			return discarded
		},

		/**
		 * 撤销当前活跃局面的最近一次成功输入。
		 */
		undo() {
			if (!game) {
				return
			}

			game.undo()
			clearTransientHints()
			publish()
		},

		/**
		 * 重做当前活跃局面最近一次被撤销的输入。
		 */
		redo() {
			if (!game) {
				return
			}

			game.redo()
			clearTransientHints()
			publish()
		},
	}
}

/**
 * 领域层 Game store 的单例。
 * 其他 store 都从这个单例派生，保证 UI 看到的是同一份游戏状态。
 * @type {ReturnType<typeof createDomainGameStore>}
 */
export const domainGame = createDomainGameStore()

/**
 * 题面网格 store。
 *
 * 该 store 只暴露 givens 给棋盘和分享功能使用，不包含玩家填写内容。
 */
export const grid = {
	/**
	 * 订阅题面网格。
	 * @param {(value: number[][]) => void} run
	 * @returns {import('svelte/store').Unsubscriber}
	 */
	subscribe(run) {
		return domainGame.subscribe(storeState => run(storeState.puzzleGrid))
	},

	/**
	 * 生成新题面并开始游戏。
	 * @param {any} difficulty
	 */
	generate(difficulty) {
		domainGame.generate(difficulty)
	},

	/**
	 * 通过分享编码恢复题面并开始游戏。
	 * @param {string} sencode
	 */
	decodeSencode(sencode) {
		domainGame.decodeSencode(sencode)
	},

	/**
	 * 读取题面网格中的单元格值。
	 * @param {number[][]} gridStore
	 * @param {number} x
	 * @param {number} y
	 * @returns {number}
	 */
	get(gridStore, x, y) {
		return gridStore[y][x]
	},

	/**
	 * 获取当前题面的分享编码。
	 * @returns {string}
	 */
	getSencode() {
		return domainGame.getSencode()
	},
}

/**
 * 玩家盘面 store。
 *
 * 该 store 暴露的是当前活跃局面：
 * 普通模式下是主局面，Explore Mode 下是探索分支局面。
 */
export const userGrid = {
	/**
	 * 订阅玩家盘面。
	 * @param {(value: number[][]) => void} run
	 * @returns {import('svelte/store').Unsubscriber}
	 */
	subscribe(run) {
		return domainGame.subscribe(storeState => run(storeState.userGrid))
	},

	/**
	 * 在指定格子写入值。
	 * @param {{x:number,y:number}|null} pos
	 * @param {number} value
	 * @returns {boolean}
	 */
	set(pos, value) {
		return domainGame.guess(pos, value)
	},

	/**
	 * 对指定格子应用直接填答案式提示。
	 * @param {{x:number,y:number}|null} pos
	 * @returns {boolean}
	 */
	applyHint(pos) {
		return domainGame.applyHint(pos)
	},

	/**
	 * 显示指定格子的候选提示。
	 * @param {{x:number,y:number}|null} pos
	 * @returns {any}
	 */
	showCellHint(pos) {
		return domainGame.showCellHint(pos)
	},

	/**
	 * 显示当前盘面的下一步提示。
	 * @returns {any}
	 */
	showNextHint() {
		return domainGame.showNextHint()
	},

	/**
	 * 清空当前显示的提示。
	 */
	clearHints() {
		domainGame.clearHints()
	},
}

/** 冲突单元格 key 列表。 */
export const invalidCells = derived(domainGame, $gameState => $gameState.invalidCells)

/** 当前活跃局面是否可以撤销。 */
export const canUndo = derived(domainGame, $gameState => $gameState.canUndo)

/** 当前活跃局面是否可以重做。 */
export const canRedo = derived(domainGame, $gameState => $gameState.canRedo)

/** 当前活跃局面是否已经完成。 */
export const gameWonState = derived(domainGame, $gameState => $gameState.won)

/** 当前显示的候选提示。 */
export const candidateHintState = derived(domainGame, $gameState => $gameState.candidateHint)

/** 当前显示的下一步提示。 */
export const nextHintState = derived(domainGame, $gameState => $gameState.nextHint)

/** 当前 Explore Mode 状态。 */
export const exploreState = derived(domainGame, $gameState => $gameState.explore)
